 * direction when that would run off the viewport:
 *
 *  - Vertical: open DOWN (top = `anchor.bottom`); if `anchor.bottom + height`
 *    would overflow the bottom edge, flip to open UP (top = `anchor.top -
 *    height`) so the menu's bottom edge meets the anchor's top.
 *  - Horizontal: open LEFT-aligned (left = `anchor.left`); if `anchor.left +
 *    width` would overflow the right edge, flip to RIGHT-align (left =
 *    `anchor.right - width`) so the menu's right edge meets the anchor's right.
 *
 * Finally the result is clamped to at least {@link MENU_EDGE_MARGIN} so a menu
 * larger than the viewport rests against the top-left corner instead of going
 * negative.
 *
 * Pure (no DOM access) so the flip behavior can be unit-tested directly with
 * arbitrary anchor / size / viewport triples; `openMenu` measures the real
 * values and feeds them in.
 */
export function computeMenuPosition(
  anchor: MenuAnchor,
  size: { width: number; height: number },
  viewport: { width: number; height: number },
): { left: number; top: number } {
  let left = anchor.left;
  let top = anchor.bottom;

  // Overflowing the right edge → open leftward (right-align to the anchor).
  if (left + size.width > viewport.width - MENU_EDGE_MARGIN) {
    left = anchor.right - size.width;
  }
  // Overflowing the bottom edge → open upward (bottom-align to the anchor).
  if (top + size.height > viewport.height - MENU_EDGE_MARGIN) {
    top = anchor.top - size.height;
  }

  // Clamp into the viewport (also covers a menu larger than the viewport).
  if (left < MENU_EDGE_MARGIN) {
    left = MENU_EDGE_MARGIN;
  }
  if (top < MENU_EDGE_MARGIN) {
    top = MENU_EDGE_MARGIN;
  }

  return { left, top };
}

/**
 * The viewport size used to flip/clamp menus. Falls back from
 * `document.documentElement.clientWidth/Height` (the layout viewport) to
 * `window.innerWidth/Height` — the fallback matters in test DOMs (e.g.
 * happy-dom) where the `<html>` element reports a 0×0 client size.
 */
function getViewportSize(): { width: number; height: number } {
  return {
    width: document.documentElement.clientWidth || window.innerWidth,
    height: document.documentElement.clientHeight || window.innerHeight,
  };
}

/**
 * Build a `.row-menu` dropdown from `items` with the shared open/close
 * lifecycle used by EVERY menu in the browse view (the per-row ⋮ menu, the
 * right-click row menu, and the current-directory blank-space menu). Returns
 * the menu element plus its `openMenu`/`closeMenu` controls.
 *
 * Lifecycle:
 *  - `openMenu(anchor)` first calls `closeAllRowMenus()` (the module-level
 *    single-open invariant — at most one menu shows at a time across every
 *    row and the directory menu), reveals the menu, measures it, and positions
 *    it at `anchor` via {@link computeMenuPosition} (flipping/clamping to stay
 *    on screen). It then registers one-shot document `click` (close on the
 *    next click anywhere — outside OR on a menu item, after the item's own
 *    handler has run) and `keydown` (close on Escape) listeners.
 *  - `closeMenu()` hides the menu, removes both listeners, and clears the
 *    module open-menu slot if it still points here.
 *
 * `btn`, when supplied (the ⋮ trigger), gets its `aria-expanded` toggled with
 * the menu; a directory menu has no trigger button, so it omits `btn`.
 */
function createMenu(
  items: HTMLElement[],
  btn?: HTMLButtonElement,
): {
  menu: HTMLElement;
  openMenu: (anchor: MenuAnchor) => void;
  closeMenu: () => void;
} {
  const menu = document.createElement('div');
  menu.className = 'row-menu';
  menu.hidden = true;
  menu.append(...items);

  // Document listeners registered on open, removed on close. Kept as named
  // references so removeEventListener tears down the exact functions.
  function onDocClick(): void {
    closeMenu();
  }
  function onDocKey(event: KeyboardEvent): void {
    if (event.key === 'Escape') {
      closeMenu();
      return;
    }
    // WAI-ARIA Menu Button keyboard contract: ArrowDown/ArrowUp move focus
    // between items (wrapping at the ends) and Home/End jump to the first /
    // last item. These are handled only while the menu is open (this listener
    // is registered by openMenu and removed by closeMenu), and they call
    // preventDefault so the keys never also scroll the page. Any other key is
    // ignored so typing / tabbing etc. behave normally.
    const count = items.length;
    if (count === 0) return;
    const current = items.findIndex((el) => el === document.activeElement);
    let next: number;
    switch (event.key) {
      case 'ArrowDown':
        // No item focused yet → land on the first; otherwise advance with wrap.
        next = current < 0 ? 0 : (current + 1) % count;
        break;
      case 'ArrowUp':
        // No item focused yet → land on the last; otherwise retreat with wrap.
        next = current < 0 ? count - 1 : (current - 1 + count) % count;
        break;
      case 'Home':
        next = 0;
        break;
      case 'End':
        next = count - 1;
        break;
      default:
        return;
    }
    event.preventDefault();
    items[next].focus();
  }

  function closeMenu(): void {
    menu.hidden = true;
    btn?.setAttribute('aria-expanded', 'false');
    document.removeEventListener('click', onDocClick);
    document.removeEventListener('keydown', onDocKey);
    if (openRowMenu?.close === closeMenu) {
      openRowMenu = null;
    }
  }

  function openMenu(anchor: MenuAnchor): void {
    closeAllRowMenus();
    menu.hidden = false;
    const rect = menu.getBoundingClientRect();
    const placement = computeMenuPosition(
      anchor,
      { width: rect.width, height: rect.height },
      getViewportSize(),
    );
    menu.style.left = placement.left + 'px';
    menu.style.top = placement.top + 'px';
    btn?.setAttribute('aria-expanded', 'true');
    document.addEventListener('click', onDocClick);
    document.addEventListener('keydown', onDocKey);
    openRowMenu = { close: closeMenu };
  }

  return { menu, openMenu, closeMenu };
}

/**
 * Build a `<table>` with a `<thead>` (one `<th>` per header label) and an empty
 * `<tbody>`. The caller appends rows to the `<tbody>`.
 */
export function buildTable(headers: string[]): HTMLTableElement {
  const table = document.createElement('table');
  table.className = 'results-table';
  const thead = document.createElement('thead');
  const headRow = document.createElement('tr');
  for (const label of headers) {
    const th = document.createElement('th');
    th.textContent = label;
    headRow.append(th);
  }
  thead.append(headRow);
  const tbody = document.createElement('tbody');
  table.append(thead, tbody);
  return table;
}

/**
 * Render clickable breadcrumb segments into the shared breadcrumb element: a
 * leading "Home" link (root) followed by one link per path segment, each
 * navigating to its cumulative path. Separators are plain '/' text spans.
 */
export function renderBreadcrumb(path: string): void {
  const breadcrumbEl = getBreadcrumb();
  breadcrumbEl.innerHTML = '';
  const normalized = normalizeRelativePath(path);
  const segments = normalized === '' ? [] : normalized.split('/');

  breadcrumbEl.append(makeNavLink('Home', toBrowseHash('')));

  let cumulative = '';
  for (const segment of segments) {
    cumulative = joinPath(cumulative, segment);
    const separator = document.createElement('span');
    separator.textContent = '/';
    breadcrumbEl.append(separator, makeNavLink(segment, toBrowseHash(cumulative)));
  }
}

/**
 * Build an `<a>` that navigates to `hash` on click. The `href` is set via
 * `setAttribute` (so the raw attribute is preserved exactly — important for
 * download URLs that must not be URL-normalized) and a click handler calls
 * `navigate(hash)` with `preventDefault` so navigation is reliable across DOM
 * implementations. The href also enables middle-click / copy-link support.
 */
export function makeNavLink(text: string, hash: string): HTMLAnchorElement {
  const link = document.createElement('a');
  link.setAttribute('href', hash);
  link.textContent = text;
  link.addEventListener('click', (event) => {
    event.preventDefault();
    navigate(hash);
  });
  return link;
}

/** The ".." parent row: a Name cell whose link navigates to the parent path. */
export function makeParentRow(parent: string): HTMLTableRowElement {
  const row = document.createElement('tr');
  row.classList.add('parent-row');
  const nameCell = document.createElement('td');
  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
  const sizeCell = document.createElement('td');
  const modifiedCell = document.createElement('td');
  const actionsCell = document.createElement('td');
  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
  // Whole-row click browses to the parent (consistent with folder rows).
  navigateRowOnClick(row, toBrowseHash(parent));
  return row;
}

/**
 * Build the per-row "⋮" action menu for a browse data row: a `.row-menu-btn`
 * (the three-dots trigger) and its `.row-menu` dropdown of action items
 * (Download for files only, then Delete / Move / Copy). Returns both elements
 * plus the row-local `openMenu(x, y)` so `makeBrowseRow` can also open the
 * SAME menu on a right-click anywhere on the row.
 *
 * Open / close lifecycle:
 *  - The button toggles: when closed, `stopPropagation()` on the opening
 *    click (so it never reaches the just-registered document listener) then
 *    `openMenu` below the button via `getBoundingClientRect()`; when open, a
 *    second click closes it.
 *  - `openMenu` first calls `closeAllRowMenus()` (only one open at a time),
 *    positions the `position: fixed` menu at viewport `(x, y)` px, reveals it,
 *    flips `aria-expanded` to `'true'`, registers one-shot document `click`
 *    (close on the next click anywhere — outside OR on a menu item, after the
 *    item's own handler has run) and `keydown` (close on Escape) listeners,
 *    and records itself as the open menu.
 *  - `closeMenu` hides the menu, restores `aria-expanded` to `'false'`, removes
 *    both document listeners, and clears `openRowMenu` if it still points here.
 *
 * The action-item handler bodies are identical to the former inline buttons
 * (same `window.confirm` / `prompt`, `getApi().delete/move/copy`,
 * `normalizeRelativePath`, and `rerender()` calls) so all behavior is
 * preserved. The items keep `class="btn"` (the `.row-menu .btn` CSS restyles
 * them into menu items) so existing query/characterization assertions hold.
 */
function makeRowMenu(entry: FileEntry): {
  btn: HTMLButtonElement;
  menu: HTMLElement;
  openMenu: (anchor: MenuAnchor) => void;
} {
  const btn = document.createElement('button');
  btn.className = 'row-menu-btn';
  btn.type = 'button';
  btn.setAttribute('aria-label', 'Actions');
  btn.setAttribute('aria-haspopup', 'true');
  btn.setAttribute('aria-expanded', 'false');
  btn.textContent = '⋮';

  // Menu items. Folders get an Upload-into-this-folder action first; files
  // get a Download anchor first. Both then get Delete / Move / Copy. Each
  // item carries a leading Bootstrap Icons glyph (see makeIcon) so the action
  // is recognizable at a glance; the label text follows.
  const items: HTMLElement[] = [];
  if (entry.isDirectory) {
    items.push(makeActionButton('Upload', () => pickAndUploadInto(entry.path), 'upload'));
  } else {
    const download = document.createElement('a');
    download.className = 'btn';
    download.setAttribute('href', getApi().downloadUrl(entry.path));
    download.setAttribute('download', entry.name);
    download.append(makeIcon('download'), 'Download');
    items.push(download);
  }
  items.push(
    makeActionButton(
      'Delete',
      async () => {
        if (!window.confirm('Delete "' + entry.name + '"?')) {
          return;
        }
        await getApi().delete(entry.path);
        rerender();
      },
      'trash',
    ),
  );
  items.push(
    makeActionButton(
      'Move',
      async () => {
        const dest = window.prompt('Move to relative destination path:', entry.path);
        if (dest === null) {
          return;
        }
        await getApi().move(entry.path, normalizeRelativePath(dest));
        rerender();
      },
      'arrows-move',
    ),
  );
  items.push(
    makeActionButton(
      'Copy',
      async () => {
        const dest = window.prompt('Copy to relative destination path:', entry.path);
        if (dest === null) {
          return;
        }
        await getApi().copy(entry.path, normalizeRelativePath(dest));
        rerender();
      },
      'files',
    ),
  );

  // Shared open/close + positioning lifecycle (see createMenu). The ⋮ button
  // is passed so its aria-expanded toggles with the menu.
  const { menu, openMenu, closeMenu } = createMenu(items, btn);

  // Toggle: open below the button, or close if already open. stopPropagation on
  // the OPENING click is critical — without it the click would bubble to the
  // document listener registered by openMenu and close the menu immediately.
  btn.addEventListener('click', (event) => {
    if (menu.hidden) {
      event.stopPropagation();
      openMenu(btn.getBoundingClientRect());
    } else {
      closeMenu();
    }
  });

  return { btn, menu, openMenu };
}

/* -------------------------------------------------------------------------
 * Current-directory context menu (right-click on blank space)
 *
 * Right-clicking the blank area of the results view (NOT on a row or the
 * header) opens a menu that acts on the CURRENTLY browsed directory: upload
 * into it, or create a new subdirectory. The menu for the current dir is
 * rebuilt on every render (the path changes with navigation) and lives as a
 * hidden `.row-menu` inside the results element; `openCurrentDirMenu` is the
 * latest menu's open function, read by the once-attached `contextmenu`
 * listener so it always targets the current directory.
 * ---------------------------------------------------------------------- */
let openCurrentDirMenu: (anchor: MenuAnchor) => void = () => {};

/**
 * Build the current-directory menu for `dirPath`: Upload (into `dirPath`) then
 * New directory (a new subdirectory under `dirPath`). Has no trigger button —
 * it is opened only by the results-view `contextmenu` listener.
 */
function makeDirMenu(dirPath: string): {
  menu: HTMLElement;
  openMenu: (anchor: MenuAnchor) => void;
} {
  const items: HTMLElement[] = [
    makeActionButton('Upload', () => pickAndUploadInto(dirPath), 'upload'),
    makeActionButton(
      'New directory',
      async () => {
        const name = window.prompt('New directory name:', '');
        // Empty / whitespace-only names (and a cancelled prompt) do nothing.
        // joinPath normalizes the combined path, and the service's SafeResolve
        // sandboxes it again, so a traversal-laden name cannot escape root.
        if (name === null || name.trim() === '') {
          return;
        }
        await getApi().createDirectory(joinPath(dirPath, name));
        rerender();
      },
      'folder-plus',
    ),
  ];
  return createMenu(items);
}

/**
 * Mount the current-directory menu for `dirPath` into `resultsEl` and wire the
 * blank-space `contextmenu` listener. Called from `renderBrowse` on every
 * render: the menu is rebuilt + re-appended each time (cleared by the render's
 * `innerHTML = ''`), while the listener attaches exactly once per results
 * element (guarded by a data attribute, since the results element persists
 * across renders within a mount).
 *
 * The listener opens the current-dir menu ONLY for genuine blank space: a
 * right-click whose target is inside the `table` (any header or data row —
 * folder/file rows handle themselves via their own listeners, and the ".."
 * parent row is navigation-only) or inside an already-open `.row-menu` is
 * ignored, so those keep their existing behavior.
 */
export function setupDirContextMenu(resultsEl: HTMLElement, dirPath: string): void {
  const { menu, openMenu } = makeDirMenu(dirPath);
  resultsEl.append(menu);
  openCurrentDirMenu = openMenu;

  if (resultsEl.dataset.dirMenuWired === '1') {
    return;
  }
  resultsEl.dataset.dirMenuWired = '1';
  resultsEl.addEventListener('contextmenu', (event) => {
    if (
      !(event.target instanceof Element) ||
      event.target.closest('table') !== null ||
      event.target.closest('.row-menu') !== null
    ) {
      return;
    }
    event.preventDefault();
    openCurrentDirMenu({
      left: event.clientX,
      top: event.clientY,
      right: event.clientX,
      bottom: event.clientY,
    });
  });
}

/** One data row in the browse table (a file or folder entry). */
export function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — directories show their immediate-child count (blank when 0);
  // files show their byte size.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatSizeColumn(entry);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  // Actions — a "⋮" dropdown button + its menu (also opened by right-clicking
  // anywhere on the row, positioned at the cursor). The action items and their
  // handlers are built by makeRowMenu; see its doc comment for the open/close
  // contract.
  const actionsCell = document.createElement('td');
  const { btn, menu, openMenu } = makeRowMenu(entry);
  actionsCell.append(btn, menu);
  row.addEventListener('contextmenu', (event) => {
    event.preventDefault();
    // Zero-size anchor at the cursor: the menu opens with its top-left at the
    // cursor (extending right/down) and flips to extend left/up only when that
    // would leave the viewport — see computeMenuPosition.
    openMenu({
      left: event.clientX,
      top: event.clientY,
      right: event.clientX,
      bottom: event.clientY,
    });
  });

  row.append(nameCell, sizeCell, modifiedCell, actionsCell);

  // A whole folder row browses into the folder on click (not just the name
  // link), EXCEPT clicks in the actions cell (the ⋮ button + its menu) which
  // keep their own behavior. The name link stays in place for middle-click /
  // copy-link accessibility; clicking it calls navigate() with the same hash,
  // and the bubbled row call repeats that same no-op (setting the hash to its
  // current value fires no hashchange, so there is no double render).
  if (entry.isDirectory) {
    row.classList.add('folder-row');
    navigateRowOnClick(row, toBrowseHash(entry.path), actionsCell);
  }

  return row;
}

/**
 * Make a table row navigate to `hash` on a click anywhere within it, so folder
 * and parent rows browse on a whole-row click rather than only on the name
 * link. Clicks originating inside `except` (e.g. a folder row's actions cell —
 * the ⋮ button and its menu) are ignored so those controls keep working.
 *
 * `event.target instanceof Node` both narrows the `EventTarget | null` target
 * to a `Node` for `Element.contains` (type-safe, no cast) and guards against a
 * null target in edge synthetic events.
 */
function navigateRowOnClick(row: HTMLTableRowElement, hash: string, except?: Element): void {
  row.addEventListener('click', (event) => {
    if (except && event.target instanceof Node && except.contains(event.target)) {
      return;
    }
    navigate(hash);
  });
}

/**
 * Build a Bootstrap Icons glyph element: an empty `<i class="bi bi-<name>">`.
 * The glyph itself is painted by the bootstrap-icons stylesheet's `::before`
 * pseudo-element (content set in CSS), so the element has NO text content of
 * its own — which keeps `textContent` assertions on the parent (e.g. a menu
 * item whose visible label is "Download") unchanged.
 */
export function makeIcon(name: string): HTMLElement {
  const icon = document.createElement('i');
  icon.className = 'bi bi-' + name;
  return icon;
}

/**
 * Build a `<button class="btn">` with the given label and click handler, and an
 * optional leading Bootstrap Icons glyph.
 *
 * The handler is wrapped so that any synchronous throw or promise rejection
 * surfaces the error via the status footer — consistent with how `render()`
 * already displays fetch errors. On normal resolution no error message is
 * shown.
 *
 * When `icon` is given it is prepended as `makeIcon(icon)` (an empty `<i>`),
 * followed by the label as a bare text node — so the button's `textContent`
 * remains exactly `label` and its `className` stays exactly `"btn"`.
 */
export function makeActionButton(
  label: string,
  handler: () => void,
  icon?: string,
): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.className = 'btn';
  btn.type = 'button';
  if (icon) {
    btn.append(makeIcon(icon));
  }
  btn.append(label);
  btn.addEventListener('click', () => {
    try {
      Promise.resolve(handler()).catch((err: unknown) => {
        getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
      });
    } catch (err) {
      getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
    }
  });
  return btn;
}

/** One data row in the search-results table. */
export function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directories browse into; files open their download URL.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    const link = document.createElement('a');
    link.setAttribute('href', getApi().downloadUrl(entry.path));
    link.textContent = entry.name;
    nameCell.append(link);
  }

  // Path
  const pathCell = document.createElement('td');
  pathCell.textContent = entry.path;

  // Size — directories show their immediate-child count (blank when 0);
  // files show their byte size.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = formatSizeColumn(entry);

  // Modified
  const modifiedCell = document.createElement('td');
  modifiedCell.textContent = formatDate(entry.lastModified);

  row.append(nameCell, pathCell, sizeCell, modifiedCell);
  return row;
}

/**
 * Hardening tests for `src/app/dom-builders.ts`.
 *
 * Two issues are addressed by the hardening change; these tests pin both the
 * unchanged contracts (so the refactor provably preserves behavior) and the
 * fixed contracts (so the bug fix is locked in):
 *
 *  1. Action-button handlers (Delete / Move / Copy / New directory) must AWAIT
 *     the `rerender()` call following each successful mutation. Before the fix
 *     the call was fire-and-forget: the handler resolved before the re-render
 *     settled and any rejection raised by the re-render was silently swallowed
 *     (an unhandled promise rejection). After the fix the handler awaits it,
 *     so a rejecting re-render propagates to `makeActionButton`'s catch wrapper
 *     and surfaces in the status footer — the same surface used for mutation
 *     errors.
 *
 *     - "re-renders after a successful mutation" (characterization): each
 *       handler still triggers a fresh browse fetch + table rebuild. Passes
 *       before AND after the await fix.
 *     - "a failing re-render surfaces in .status" (fix verification): requires
 *       `await rerender()`; fails before the fix, passes after.
 *
 *  2. Menu open/close state (`openRowMenu` / `openCurrentDirMenu`) is
 *     encapsulated per mount (a `createMenuState()` factory threaded through
 *     the shared context) so a re-mount never inherits a previous mount's
 *     stale menu state. The within-mount menu contract (open/close, single-open
 *     invariant, keyboard nav, the row + directory context menus) must hold
 *     unchanged after a re-mount. The cross-mount contamination (a stale close
 *     function from the previous mount closing the old menu) is the bug the
 *     encapsulation fixes.
 *
 * Environment: happy-dom (these tests need a DOM). Shared fixtures and the
 * per-test fetch stub come from `./test-helpers`.
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { renderBrowse } from '../app';
import { setRenderHook } from './context';
import { mockResponse } from '../test-utils/mock-response';
import {
  setupCleared,
  flush,
  browseResult,
  fileEntry,
  rowByName,
  cellsOf,
  buttonsByText,
  fetchMock,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

const FILE = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 10 });

/** The Actions cell (4th td) of the data row whose Name cell matches `name`. */
function actionsOf(results: HTMLElement, name: string): Element {
  return cellsOf(rowByName(results.querySelector('table')!, name)!)[3];
}

/** The current-directory menu: the `.row-menu` that is a direct child of `.results`. */
function dirMenuOf(results: HTMLElement): HTMLElement {
  const menu = Array.from(results.children).find(
    (c) => c instanceof HTMLElement && c.classList.contains('row-menu'),
  ) as HTMLElement | undefined;
  if (!menu) {
    throw new Error('directory menu (.results > .row-menu) not found');
  }
  return menu;
}

/**
 * Safety net: tests below override the shared render hook (`setRenderHook`) to
 * inject a failing re-render. Neutralize the hook after every test so a
 * throwing hook can never leak into a later test; each test's `setupCleared()`
 * re-binds the real render via the orchestrator's `init()` before it runs.
 */
afterEach(() => {
  setRenderHook(async () => {});
});

/* ===========================================================================
 * Issue 1 — characterization: mutation handlers re-render on success
 *
 * Passes before AND after the `await rerender()` fix. Locks in that each
 * handler still calls rerender() (a fresh browse fetch + table rebuild) after a
 * successful mutation, so the fix cannot accidentally drop the re-render.
 * ========================================================================= */
describe('action handlers re-render after a successful mutation', () => {
  it('Delete: re-renders so the deleted file is gone from the table', async () => {
    let deleted = false;
    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const m = (init?.method ?? 'GET').toUpperCase();
      if (m === 'DELETE' && u.includes('/delete')) {
        deleted = true;
        return mockResponse({ status: 200, body: {} });
      }
      if (m === 'GET' && u.includes('/browse')) {
        const entries = deleted ? [] : [FILE];
        return mockResponse({
          body: browseResult({
            path: 'docs',
            entries,
            fileCount: deleted ? 0 : 1,
            totalSize: deleted ? 0 : 10,
          }),
        });
      }
      return mockResponse({ status: 200, body: {} });
    });

    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));
    vi.spyOn(window, 'confirm').mockReturnValue(true);

    buttonsByText(actionsOf(results, 'a.txt'), 'Delete')[0].click();
    await flush();
    await flush();
    await flush();

    expect(deleted).toBe(true);
    // The re-render fetched an empty listing, so the row is gone.
    expect(rowByName(results.querySelector('table')!, 'a.txt')).toBeUndefined();
  });

  it('Move: calls api.move then re-renders (fetches browse again)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));
    vi.spyOn(window, 'prompt').mockReturnValue('docs/archive/a.txt');

    const browseBefore = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse')).length;

    buttonsByText(actionsOf(results, 'a.txt'), 'Move')[0].click();
    await flush();
    await flush();
    await flush();

    const moveCalls = fetchMock.mock.calls.filter(
      ([u, init]) => String(u).includes('/move') && (init?.method ?? 'GET') === 'POST',
    );
    expect(moveCalls).toHaveLength(1);
    // rerender() fired a fresh browse fetch.
    const browseAfter = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse')).length;
    expect(browseAfter).toBeGreaterThan(browseBefore);
  });

  it('Copy: calls api.copy then re-renders (fetches browse again)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));
    vi.spyOn(window, 'prompt').mockReturnValue('docs/copy/a.txt');

    const browseBefore = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse')).length;

    buttonsByText(actionsOf(results, 'a.txt'), 'Copy')[0].click();
    await flush();
    await flush();
    await flush();

    const copyCalls = fetchMock.mock.calls.filter(
      ([u, init]) => String(u).includes('/copy') && (init?.method ?? 'GET') === 'POST',
    );
    expect(copyCalls).toHaveLength(1);
    const browseAfter = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse')).length;
    expect(browseAfter).toBeGreaterThan(browseBefore);
  });

  it('New directory: re-renders so the new subdirectory appears in the table', async () => {
    let created = false;
    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const m = (init?.method ?? 'GET').toUpperCase();
      if (m === 'POST' && u.includes('/mkdir')) {
        created = true;
        return mockResponse({ status: 200, body: {} });
      }
      if (m === 'GET' && u.includes('/browse')) {
        const entries = created
          ? [fileEntry({ name: 'new folder', path: 'docs/new folder', isDirectory: true })]
          : [];
        return mockResponse({
          body: browseResult({ path: 'docs', entries, folderCount: created ? 1 : 0 }),
        });
      }
      return mockResponse({ status: 200, body: {} });
    });

    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));
    vi.spyOn(window, 'prompt').mockReturnValue('new folder');

    buttonsByText(dirMenuOf(results), 'New directory')[0].click();
    await flush();
    await flush();
    await flush();

    expect(created).toBe(true);
    expect(rowByName(results.querySelector('table')!, 'new folder')).toBeTruthy();
  });
});

/* ===========================================================================
 * Issue 1 — fix verification: handlers AWAIT rerender()
 *
 * A rejecting re-render must propagate to makeActionButton's catch wrapper and
 * surface in the status footer. This only happens once `rerender()` is awaited;
 * the fire-and-forget call silently swallows the rejection. We inject a failing
 * re-render by overriding the shared render hook (setRenderHook) AFTER setup —
 * the orchestrator's hashchange listener calls the LOCAL render function (not
 * the hook), so the override affects ONLY rerender() callers.
 *
 * These tests FAIL before the await fix (the status footer is unchanged) and
 * PASS after it. (Delete and New directory cover the two distinct code
 * locations — makeRowMenu and makeDirMenu; Move and Copy share makeRowMenu's
 * Delete-shaped handler, so they are covered transitively.) The PRE-fix
 * un-awaited rerender() leaves an unhandled rejection; a process-level handler
 * in beforeEach keeps the (expected, pre-fix) assertion failure clean rather
 * than noisy with an unhandled-rejection report. Post-fix there is no unhandled
 * rejection, so the handler swallows nothing.
 * ========================================================================= */
describe('action handlers await rerender() — a failing re-render surfaces in .status', () => {
  // Swallow the unhandled rejection produced by the PRE-fix un-awaited
  // rerender() so each test fails cleanly on its assertion. process is the
  // Node global vitest runs under (the happy-dom DOM shim does not change this).
  const swallow = (): void => {};
  beforeEach(() => {
    process.on('unhandledRejection', swallow);
  });
  afterEach(() => {
    process.off('unhandledRejection', swallow);
  });

  it('Delete: a failing re-render after a successful delete surfaces in .status', async () => {
    const { results, status } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));
    setRenderHook(async () => {
      throw new Error('re-render failed');
    });
    vi.spyOn(window, 'confirm').mockReturnValue(true);

    buttonsByText(actionsOf(results, 'a.txt'), 'Delete')[0].click();
    await flush();
    await flush();

    // With `await rerender()`, the handler rejects and makeActionButton surfaces
    // the error in the status footer (same surface as mutation errors).
    expect(status.textContent).toBe('Error: re-render failed');
  });

  it('New directory: a failing re-render after a successful mkdir surfaces in .status', async () => {
    const { results, status } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));
    setRenderHook(async () => {
      throw new Error('re-render failed');
    });
    vi.spyOn(window, 'prompt').mockReturnValue('new folder');

    buttonsByText(dirMenuOf(results), 'New directory')[0].click();
    await flush();
    await flush();

    expect(status.textContent).toBe('Error: re-render failed');
  });
});

/* ===========================================================================
 * Issue 2 — per-mount menu state: behavior across a re-mount
 *
 * Encapsulating openRowMenu / openCurrentDirMenu in a per-mount object must not
 * change the within-mount menu contract. The first three tests verify the full
 * menu behavior (open/close, single-open invariant, keyboard nav, the row +
 * directory context menus) still works in the NEWEST mount after a previous
 * mount has populated (and, pre-fix, left behind) module-level state. They pass
 * before AND after the encapsulation.
 *
 * The last test verifies the actual contamination fix: a row menu left open in
 * a PREVIOUS mount must NOT be closed when the new mount opens its own menu
 * (module-level state used to call the previous mount's stale close function).
 * It fails before the encapsulation and passes after.
 * ========================================================================= */
describe('menu state across a re-mount', () => {
  // Close any menu left open by a prior test (Escape is handled by an open
  // menu's document keydown listener; idempotent no-op when none is open) so
  // every test starts — and, via afterEach, ends — with a clean menu slate.
  // This also tears down any document click/keydown listeners an open menu
  // registered, so they cannot leak into the next test.
  beforeEach(() => {
    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
  });
  afterEach(() => {
    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
  });

  it('after a re-mount, the ⋮ row menu opens/closes and only one is open at a time', async () => {
    await setupCleared(); // first mount (populates module-level state)
    const { results } = await setupCleared(); // re-mount (under test)
    renderBrowse(
      browseResult({
        path: 'docs',
        entries: [
          fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 10 }),
          fileEntry({ name: 'b.txt', path: 'docs/b.txt', isDirectory: false, size: 20 }),
        ],
      }),
    );

    const actionsA = actionsOf(results, 'a.txt');
    const actionsB = actionsOf(results, 'b.txt');
    const menuA = actionsA.querySelector('.row-menu') as HTMLElement;
    const menuB = actionsB.querySelector('.row-menu') as HTMLElement;
    const btnA = actionsA.querySelector('.row-menu-btn') as HTMLButtonElement;
    const btnB = actionsB.querySelector('.row-menu-btn') as HTMLButtonElement;

    btnA.click();
    expect(menuA.hidden).toBe(false);
    expect(btnA.getAttribute('aria-expanded')).toBe('true');

    // Opening B closes A (single-open invariant).
    btnB.click();
    expect(menuB.hidden).toBe(false);
    expect(menuA.hidden).toBe(true);
    expect(btnA.getAttribute('aria-expanded')).toBe('false');

    // A click anywhere outside closes the open menu.
    const outside = document.createElement('div');
    document.body.append(outside);
    outside.click();
    outside.remove();
    expect(menuB.hidden).toBe(true);
    expect(btnB.getAttribute('aria-expanded')).toBe('false');
  });

  it('after a re-mount, the right-click row menu and the blank-space directory menu both open at the cursor', async () => {
    await setupCleared();
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));

    // Right-click the row opens the row menu at the cursor.
    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
    const rowMenu = actionsOf(results, 'a.txt').querySelector('.row-menu') as HTMLElement;
    row.dispatchEvent(
      new MouseEvent('contextmenu', { cancelable: true, bubbles: true, clientX: 30, clientY: 40 }),
    );
    expect(rowMenu.hidden).toBe(false);
    expect(rowMenu.style.left).toBe('30px');

    // Close it, then right-click blank space opens the directory menu.
    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
    expect(rowMenu.hidden).toBe(true);

    const dirMenu = dirMenuOf(results);
    const evt = new MouseEvent('contextmenu', {
      cancelable: true,
      bubbles: true,
      clientX: 50,
      clientY: 80,
    });
    results.dispatchEvent(evt);
    expect(evt.defaultPrevented).toBe(true);
    expect(dirMenu.hidden).toBe(false);
    expect(dirMenu.style.left).toBe('50px');
  });

  it('after a re-mount, keyboard navigation (ArrowDown / End) still moves focus between items', async () => {
    await setupCleared();
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));

    const actions = actionsOf(results, 'a.txt');
    (actions.querySelector('.row-menu-btn') as HTMLButtonElement).click();
    const menu = actions.querySelector('.row-menu') as HTMLElement;
    const items = Array.from(menu.children) as HTMLElement[];
    expect(menu.hidden).toBe(false);

    items[0].focus();
    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'ArrowDown', cancelable: true }));
    expect(document.activeElement).toBe(items[1]);

    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'End', cancelable: true }));
    expect(document.activeElement).toBe(items[items.length - 1]);
  });

  it('a row menu left open in a PREVIOUS mount is not closed when the new mount opens its own menu (per-mount isolation)', async () => {
    // The encapsulation fix: each mount owns its own menu-state slot. With
    // module-level `openRowMenu`, re-mounting did NOT reset it, so opening a
    // menu in the new mount called closeAllRowMenus() → the PREVIOUS mount's
    // stale close function, hiding the old (now-detached) menu. With per-mount
    // state the new mount never touches the previous mount's menu.
    const ctx1 = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));
    const menu1 = actionsOf(ctx1.results, 'a.txt').querySelector('.row-menu') as HTMLElement;
    const btn1 = actionsOf(ctx1.results, 'a.txt').querySelector(
      '.row-menu-btn',
    ) as HTMLButtonElement;
    btn1.click();
    expect(menu1.hidden).toBe(false); // mount #1's menu is open

    // Re-mount: document.body is cleared (menu1 is detached but still
    // referenced). Pre-fix, the module-level openRowMenu still points at
    // menu1's close function.
    const ctx2 = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [FILE] }));
    const btn2 = actionsOf(ctx2.results, 'a.txt').querySelector(
      '.row-menu-btn',
    ) as HTMLButtonElement;
    const menu2 = actionsOf(ctx2.results, 'a.txt').querySelector('.row-menu') as HTMLElement;

    btn2.click(); // open mount #2's menu

    expect(menu2.hidden).toBe(false); // mount #2's menu opened
    // Per-mount isolation: the previous mount's menu is untouched. (Pre-fix the
    // stale close ran here, setting menu1.hidden = true, so this fails until
    // the state is encapsulated per mount.)
    expect(menu1.hidden).toBe(false);
  });
});

/**
 * Shared test helpers for the `src/app/*.test.ts` per-domain test files.
 *
 * Extracted verbatim from the former `src/app.test.ts` monolith (split per
 * task-29) so each focused test file can import only what it needs. Houses:
 *
 *   - fixture builders: `fileEntry`, `browseResult`, `joinPathHelper`,
 *     `browseRoute`, `searchRoute`
 *   - timing: `flush`
 *   - DOM scaffolding: `setup`, `setupCleared`, `SetupCtx`
 *   - table/row traversal: `dataRows`, `rowByName`, `cellsOf`,
 *     `clickNameLink`, `buttonsByText`
 *   - the shared per-test fetch stub lifecycle: `installAppTestLifecycle` plus
 *     the `fetchMock` live binding it rebinds each test
 *
 * `browseRoute` / `searchRoute` construct `Route` fixtures. They were
 * referenced by the dead-CSS characterization suite in the monolith but never
 * defined (a latent bug that left those tests throwing `ReferenceError`); they
 * are defined here so those scenarios finally run. `renderBrowse` /
 * `renderSearch` no longer take a `route` argument (its removal is pinned by
 * the route-independence suite), so the value is ignored at runtime — but it
 * must be a defined expression rather than a bare `ReferenceError`.
 *
 * Test-only utility: deliberately kept out of the production `tsc` build via
 * the `src/app/test-helpers.ts` entry in `tsconfig.json`'s `exclude` array
 * (mirroring the `src/test-utils/**` glob added by task-27), so it is never
 * shipped to `wwwroot/dist`. Only test files import it.
 */
import { vi, beforeEach, afterEach } from 'vitest';
import { startApp } from '../app';
import type { BrowseResult, FileEntry, SearchResult } from '../api';
import type { Route } from '../router';
import { mockResponse } from '../test-utils/mock-response';

/* ===========================================================================
 * Constants & fixture builders
 * ========================================================================= */

export const ISO = '2024-03-15T10:30:00'; // offset-free → parsed as local time
export const ISO_FMT = '2024-03-15 10:30'; // expected formatDate(...) output

export function fileEntry(opts: Partial<FileEntry> & { name: string }): FileEntry {
  return {
    name: opts.name,
    path: opts.path ?? joinPathHelper('docs', opts.name),
    isDirectory: opts.isDirectory ?? false,
    size: opts.size ?? 0,
    lastModified: opts.lastModified ?? ISO,
    itemCount: opts.itemCount ?? 0,
  };
}

export function browseResult(opts: Partial<BrowseResult> = {}): BrowseResult {
  return {
    path: opts.path ?? '',
    parent: opts.parent ?? null,
    entries: opts.entries ?? [],
    folderCount: opts.folderCount ?? 0,
    fileCount: opts.fileCount ?? 0,
    totalSize: opts.totalSize ?? 0,
  };
}

// local join to avoid pulling joinPath into the test's asserted import set
export function joinPathHelper(base: string, name: string): string {
  return (base ? base + '/' : '') + name;
}

/** Build a browse `Route` fixture. */
export function browseRoute(path: string): Route {
  return { view: 'browse', path, query: '' };
}

/** Build a search `Route` fixture. */
export function searchRoute(query: string, path: string = ''): Route {
  return { view: 'search', query, path };
}

/* ===========================================================================
 * Timing
 * ========================================================================= */

/** Let pending microtasks / queued hashchange renders settle. */
export const flush = (): Promise<void> => new Promise((r) => setTimeout(r, 0));

/* ===========================================================================
 * DOM scaffolding
 * ========================================================================= */

export interface SetupCtx {
  root: HTMLElement;
  embeddedHost: HTMLElement;
  widget: HTMLElement;
  dialog: HTMLDialogElement;
  trigger: HTMLButtonElement;
  closeBtn: HTMLButtonElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
  searchWrapper: HTMLElement;
  searchClearBtn: HTMLButtonElement;
  searchIcon: HTMLElement;
  results: HTMLElement;
  status: HTMLElement;
}

/**
 * Build a fresh app inside a fresh container. Clears `document.body` first so
 * every test is independent (no leakage of elements, and document-scoped
 * queries inside `renderBrowse`/`renderSearch` always resolve to the current
 * test's DOM).
 */
export function setup(options: { hash?: string } = {}): SetupCtx {
  document.body.innerHTML = '';
  window.location.hash = options.hash ?? '';

  const root = document.createElement('div');
  document.body.append(root);
  startApp(root);

  return {
    root,
    embeddedHost: root.querySelector('.file-browser-host') as HTMLElement,
    widget: root.querySelector('.file-browser') as HTMLElement,
    dialog: root.querySelector('dialog.browser-dialog') as HTMLDialogElement,
    trigger: root.querySelector('button.trigger') as HTMLButtonElement,
    closeBtn: root.querySelector('.close-btn') as HTMLButtonElement,
    breadcrumb: root.querySelector('.breadcrumb') as HTMLElement,
    searchInput: root.querySelector('input[type="text"]') as HTMLInputElement,
    searchWrapper: root.querySelector('.search-wrapper') as HTMLElement,
    searchClearBtn: root.querySelector('.search-wrapper .clear-btn') as HTMLButtonElement,
    searchIcon: root.querySelector('.search-wrapper .search-icon') as HTMLElement,
    results: root.querySelector('.results') as HTMLElement,
    status: root.querySelector('.status') as HTMLElement,
  };
}

/**
 * `setup()` plus a flush (so startApp's initial `render()` settles) and a clear
 * of `.results`, mimicking what `render()` does before delegating to
 * `renderBrowse`/`renderSearch`. Used by tests that exercise those helpers
 * directly so their assertions are isolated from the initial render's output.
 */
export async function setupCleared(options: { hash?: string } = {}): Promise<SetupCtx> {
  const ctx = setup(options);
  await flush();
  ctx.results.innerHTML = '';
  return ctx;
}

/* ===========================================================================
 * Table-traversal helpers (browser-agnostic; work on Element).
 * ========================================================================= */

export function dataRows(table: Element): Element[] {
  return Array.from(table.querySelectorAll('tbody tr'));
}
export function rowByName(table: Element, name: string): Element | undefined {
  return dataRows(table).find((tr) => (tr.querySelector('td')?.textContent ?? '').trim() === name);
}
export function cellsOf(row: Element): Element[] {
  return Array.from(row.querySelectorAll('td'));
}
export function clickNameLink(row: Element): void {
  const nameCell = cellsOf(row)[0];
  const link = nameCell.querySelector('a, button') as HTMLElement | null;
  (link ?? (nameCell as HTMLElement)).click();
}
export function buttonsByText(container: Element, text: string): HTMLButtonElement[] {
  return Array.from(container.querySelectorAll('button')).filter(
    (b) => (b.textContent ?? '').trim() === text,
  );
}

/* ===========================================================================
 * Shared per-test fetch stub lifecycle
 *
 * `fetchMock` is an `export let` live binding: `installAppTestLifecycle()`'s
 * `beforeEach` rebinds it to a fresh permissive `vi.fn` each test, and every
 * importer sees the rebound value (ESM live bindings — verified against this
 * vitest setup). Tests therefore read `fetchMock.mock.calls` exactly as the
 * monolith did, with no per-file `let fetchMock` declaration.
 * ========================================================================= */

export let fetchMock: ReturnType<typeof vi.fn> = vi.fn(async () => mockResponse({ body: {} }));

/**
 * Register the shared `beforeEach` (permissive default fetch stub) and
 * `afterEach` (DOM + mock cleanup) used by every split app test file. Call
 * exactly once at module top level in each `*.test.ts`.
 */
export function installAppTestLifecycle(): void {
  beforeEach(() => {
    // A permissive default: every browse/search GET returns a recognizable
    // result derived from the requested path/query, and every mutation returns
    // 200. Individual tests override with `fetchMock.mockImplementation(...)`
    // or `.mockResolvedValueOnce(...)` for specific scenarios. This also means
    // incidental background renders (e.g. from accumulated hashchange
    // listeners) never throw unhandled rejections.
    fetchMock = vi.fn(async (url: string, init?: RequestInit) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      return mockResponse({ status: 200, body: {} });
    });
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    // NOTE: do NOT touch window.location.hash here. In happy-dom, assigning to
    // location.hash dispatches `hashchange` synchronously. startApp unsubscribes
    // the previous mount's render() listener on re-mount (so listeners no longer
    // accumulate across tests), but the CURRENT test's listener remains active
    // until the next test's setup() re-mounts. Resetting the hash after
    // `vi.unstubAllGlobals()` would therefore drive a render through the REAL
    // fetch. We clear the body first (while fetch is still stubbed, so any
    // in-flight render's already-issued request stays mocked) and reset the hash
    // at the start of the next test's setup() instead.
    document.body.innerHTML = '';
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });
}

/**
 * Shared services for the file-browser app modules.
 *
 * The file-browser is split across several focused modules (dom-builders,
 * render-browse, render-search, toolbar-handlers, render-orchestrator). They
 * all need access to three cross-cutting things that `startApp` establishes
 * once per mount:
 *
 *   - the {@link ApiClient} singleton (used for fetches and download URLs);
 *   - the DOM element refs the render helpers write into (results, status,
 *     breadcrumb, search input);
 *   - a "render hook" that action-button handlers and the upload handler call
 *     to trigger a fresh route dispatch (used instead of importing the
 *     orchestrator directly, which would create a module cycle: orchestrator →
 *     render-browse → dom-builders → orchestrator).
 *
 * Centralizing them here keeps the cross-module dependency graph acyclic and
 * makes the re-bind-on-remount contract explicit — replacing the bare
 * module-level `let resultsEl!: HTMLElement` variables that used to live in
 * `app.ts`. `render-orchestrator.init` re-binds the refs every mount, so the
 * render helpers always target the most recently mounted app.
 */
import { ApiClient } from '../api.js';

/** The DOM element refs established by each `startApp` mount. */
export interface DomRefs {
  results: HTMLElement;
  status: HTMLElement;
  breadcrumb: HTMLElement;
  searchInput: HTMLInputElement;
}

/* -------------------------------------------------------------------------
 * API singleton
 *
 * Created once at module load, exactly as the original `app.ts` created
 * `const api = new ApiClient();` at its top level. The constructor performs
 * no I/O, so creating it before `fetch` is stubbed in a test is safe.
 * ---------------------------------------------------------------------- */
const api = new ApiClient();

/** The shared API client (used for fetches and download-URL construction). */
export function getApi(): ApiClient {
  return api;
}

/* -------------------------------------------------------------------------
 * DOM refs — rebound by `render-orchestrator.init` on every `startApp` mount
 * so `renderBrowse` / `renderSearch` always target the most recent mount.
 *
 * The definite-assignment assertions mirror the original `let resultsEl!:
 * HTMLElement` pattern: the refs are uninitialized only until the first
 * `init()` call, which always runs before any render helper reads them.
 * ---------------------------------------------------------------------- */
let results!: HTMLElement;
let status!: HTMLElement;
let breadcrumb!: HTMLElement;
let searchInput!: HTMLInputElement;

/** Bind the DOM refs for the current mount. Called from the orchestrator's `init`. */
export function setRefs(refs: DomRefs): void {
  results = refs.results;
  status = refs.status;
  breadcrumb = refs.breadcrumb;
  searchInput = refs.searchInput;
}

export function getResults(): HTMLElement {
  return results;
}

export function getStatus(): HTMLElement {
  return status;
}

export function getBreadcrumb(): HTMLElement {
  return breadcrumb;
}

export function getSearchInput(): HTMLInputElement {
  return searchInput;
}

/* -------------------------------------------------------------------------
 * Render hook
 *
 * Action-button handlers (in dom-builders) and the upload handler (in
 * toolbar-handlers) call `rerender()` to trigger a fresh route dispatch. They
 * cannot import `render` from render-orchestrator.ts directly without creating
 * the cycle noted above, so the orchestrator registers its `render` function
 * here during `init` and the callers invoke it indirectly through `rerender`.
 * ---------------------------------------------------------------------- */
let renderHook: () => Promise<void> = async () => {};

/** Register the route-dispatching render function. */
export function setRenderHook(fn: () => Promise<void>): void {
  renderHook = fn;
}

/** Trigger a fresh render via the registered hook. No-op until `setRenderHook` is called. */
export function rerender(): Promise<void> {
  return renderHook();
}

/**
 * Tests for the row-menu placement helpers in `dom-builders.ts`:
 *
 *  - `computeMenuPosition` — the pure off-screen flip math (no DOM). By
 *    default a menu opens below + left-aligned with its anchor; when that
 *    would run off a viewport edge it flips direction (down→up, left→right)
 *    and is finally clamped inside the viewport.
 *  - `openMenu` wiring — when a row menu is opened, its real measured size
 *    and the live viewport size are fed into `computeMenuPosition`, so the
 *    flip actually takes effect (not just the pure function in isolation).
 *
 * Environment: happy-dom, which performs NO layout (`getBoundingClientRect`
 * always reports width/height 0). The pure suite is therefore independent of
 * the DOM, and the wiring test injects a synthetic menu rect + viewport via
 * spies/assignment rather than relying on rendered geometry.
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { computeMenuPosition, MENU_EDGE_MARGIN, makeIcon, makeActionButton } from './dom-builders';
import { renderBrowse } from '../app';
import {
  setupCleared,
  browseResult,
  fileEntry,
  rowByName,
  cellsOf,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* A typical ⋮ button rect and a menu size, used across the pure suite. */
const BTN = { left: 900, top: 200, right: 920, bottom: 224 };
const SIZE = { width: 160, height: 140 };
const VIEW = { width: 1000, height: 600 };

describe('computeMenuPosition — default (no overflow)', () => {
  it('opens below + left-aligned with the anchor: left=anchor.left, top=anchor.bottom', () => {
    const anchor = { left: 100, top: 200, right: 120, bottom: 224 };
    const p = computeMenuPosition(anchor, SIZE, VIEW);
    expect(p).toEqual({ left: 100, top: 224 });
  });

  it('keeps the cursor coords for a zero-size (right-click) anchor that fits', () => {
    const cursor = { left: 137, top: 242, right: 137, bottom: 242 };
    const p = computeMenuPosition(cursor, SIZE, VIEW);
    expect(p).toEqual({ left: 137, top: 242 });
  });
});

describe('computeMenuPosition — horizontal flip (would overflow the right edge)', () => {
  it('right-aligns the menu to the anchor right edge instead (open leftward)', () => {
    // anchor.left(900) + width(160) = 1060 > viewport(1000) - margin → flip.
    const p = computeMenuPosition(BTN, SIZE, VIEW);
    expect(p.left).toBe(BTN.right - SIZE.width); // 920 - 160 = 760
    expect(p.top).toBe(BTN.bottom); // vertical still fits → unchanged
  });

  it('right-click near the right edge flips so the menu extends left of the cursor', () => {
    const cursor = { left: 980, top: 100, right: 980, bottom: 100 };
    const p = computeMenuPosition(cursor, SIZE, VIEW);
    expect(p.left).toBe(980 - 160); // 820
  });

  it('does NOT flip when the menu fits within the margin of the right edge', () => {
    // 836 + 160 = 996 == viewport(1000) - margin(4): exactly at the limit, fits.
    const anchor = { left: 836, top: 200, right: 856, bottom: 224 };
    expect(computeMenuPosition(anchor, SIZE, VIEW).left).toBe(836);
  });
});

describe('computeMenuPosition — vertical flip (would overflow the bottom edge)', () => {
  it('opens upward, aligning the menu bottom to the anchor top', () => {
    // anchor.bottom(500) + height(140) = 640 > viewport(600) - margin → flip.
    const anchor = { left: 100, top: 476, right: 120, bottom: 500 };
    const p = computeMenuPosition(anchor, SIZE, VIEW);
    expect(p.top).toBe(anchor.top - SIZE.height); // 476 - 140 = 336
    expect(p.left).toBe(anchor.left); // horizontal still fits → unchanged
  });

  it('right-click near the bottom flips so the menu extends above the cursor', () => {
    const cursor = { left: 100, top: 580, right: 100, bottom: 580 };
    const p = computeMenuPosition(cursor, SIZE, VIEW);
    expect(p.top).toBe(580 - 140); // 440
  });
});

describe('computeMenuPosition — both axes flip at once', () => {
  it('right-aligns AND opens upward when the anchor is in the bottom-right corner', () => {
    const anchor = { left: 900, top: 476, right: 920, bottom: 500 };
    const p = computeMenuPosition(anchor, SIZE, VIEW);
    expect(p).toEqual({ left: 760, top: 336 });
  });
});

describe('computeMenuPosition — clamping into the viewport', () => {
  it('clamps left to the edge margin when a flip would push it off the left edge', () => {
    // Cursor near the left edge + a menu wider than the tiny viewport: the
    // right-align flip computes left = 10 - 160 = -150, which clamps to the
    // margin.
    const tinyView = { width: 100, height: 600 };
    const cursor = { left: 10, top: 200, right: 10, bottom: 224 };
    const p = computeMenuPosition(cursor, SIZE, tinyView);
    expect(p.left).toBe(MENU_EDGE_MARGIN);
  });

  it('clamps top to the edge margin when opening upward would go above the top', () => {
    const tinyView = { width: 1000, height: 100 };
    const anchor = { left: 100, top: 40, right: 120, bottom: 60 };
    const p = computeMenuPosition(anchor, SIZE, tinyView);
    expect(p.top).toBe(MENU_EDGE_MARGIN);
  });
});

/* ===========================================================================
 * makeIcon / makeActionButton — Bootstrap Icons glyphs on menu items.
 *
 * makeIcon builds an empty `<i class="bi bi-<name>">` (the glyph is painted by
 * the bootstrap-icons CSS ::before, so the element has no text content).
 * makeActionButton prepends that glyph when given an `icon` arg, and otherwise
 * behaves exactly as before (label-only, className exactly "btn").
 * ========================================================================= */
describe('makeIcon', () => {
  it('builds an empty <i class="bi bi-<name>"> with no text content', () => {
    const icon = makeIcon('trash');
    expect(icon.tagName).toBe('I');
    expect(icon.className).toBe('bi bi-trash');
    expect(icon.textContent).toBe('');
    expect(icon.children).toHaveLength(0);
  });
});

describe('makeActionButton — icon support', () => {
  it('with an icon: prepends an empty <i class="bi bi-<name>"> as the first child and keeps className exactly "btn"', () => {
    const btn = makeActionButton('Delete', () => undefined, 'trash');
    expect(btn.tagName).toBe('BUTTON');
    expect(btn.className).toBe('btn');
    expect(btn.getAttribute('type')).toBe('button');
    expect(btn.children).toHaveLength(1);
    const icon = btn.firstElementChild as HTMLElement;
    expect(icon.tagName).toBe('I');
    expect(icon.className).toBe('bi bi-trash');
    // The icon adds no text, so the button's textContent is still just the label.
    expect(btn.textContent).toBe('Delete');
  });

  it('without an icon: has no child elements and textContent is the label (default unchanged)', () => {
    const btn = makeActionButton('Search', () => undefined);
    expect(btn.children).toHaveLength(0);
    expect(btn.textContent).toBe('Search');
    expect(btn.className).toBe('btn');
  });
});

/* ===========================================================================
 * openMenu wiring — the measured menu size + live viewport drive the flip.
 *
 * happy-dom reports a 0×0 rect for every element, so we spy on the menu's
 * getBoundingClientRect to inject a known size and shrink window.innerWidth/
 * innerHeight to force an overflow, then assert the menu's inline left/top
 * match what computeMenuPosition would produce.
 * ========================================================================= */
describe('openMenu applies computeMenuPosition to the rendered menu', () => {
  const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 10 });

  let savedW: number;
  let savedH: number;

  beforeEach(() => {
    savedW = window.innerWidth;
    savedH = window.innerHeight;
    // Ensure no menu is left open by a prior test.
    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
  });
  afterEach(() => {
    window.innerWidth = savedW;
    window.innerHeight = savedH;
  });

  function menuOf(results: HTMLElement): HTMLElement {
    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
    return cellsOf(row)[3].querySelector('.row-menu') as HTMLElement;
  }

  it('flips up + right when the right-click point is in the bottom-right corner', async () => {
    window.innerWidth = 1000;
    window.innerHeight = 600;
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));
    const menu = menuOf(results);
    vi.spyOn(menu, 'getBoundingClientRect').mockReturnValue({
      left: 0,
      top: 0,
      right: 160,
      bottom: 140,
      width: 160,
      height: 140,
      x: 0,
      y: 0,
      toJSON() {},
    });

    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
    row.dispatchEvent(
      new MouseEvent('contextmenu', {
        cancelable: true,
        bubbles: true,
        clientX: 900,
        clientY: 500,
      }),
    );

    // Cursor anchor {900,500,900,500}, size 160×140, viewport 1000×600:
    // horizontal flip → left = 900 - 160 = 740; vertical flip → top = 500 - 140 = 360.
    expect(menu.hidden).toBe(false);
    expect(menu.style.left).toBe('740px');
    expect(menu.style.top).toBe('360px');
  });

  it('leaves the cursor position untouched when the menu fits (no measured overflow)', async () => {
    // Default happy-dom viewport (1024×768) with a measured size that fits.
    window.innerWidth = 1024;
    window.innerHeight = 768;
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));
    const menu = menuOf(results);
    vi.spyOn(menu, 'getBoundingClientRect').mockReturnValue({
      left: 0,
      top: 0,
      right: 160,
      bottom: 60,
      width: 160,
      height: 60,
      x: 0,
      y: 0,
      toJSON() {},
    });

    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
    row.dispatchEvent(
      new MouseEvent('contextmenu', {
        cancelable: true,
        bubbles: true,
        clientX: 137,
        clientY: 242,
      }),
    );

    expect(menu.hidden).toBe(false);
    expect(menu.style.left).toBe('137px');
    expect(menu.style.top).toBe('242px');
  });
});

/**
 * Route dispatcher and rendering-lifecycle owner.
 *
 * `render` reads the current route, fetches the matching result from the API,
 * and delegates to `renderBrowse` / `renderSearch`. It guards against render
 * races (a slower, superseded fetch cannot clobber fresher results) via a
 * monotonic token checked after each `await`.
 *
 * `init` is called once per `startApp` mount: it binds the freshly-built DOM
 * refs into the shared context, registers `render` as the re-render hook (so
 * action buttons and uploads can trigger it without a circular import), tears
 * down any previous mount's hashchange listener, subscribes a new one, and
 * kicks off the initial render.
 */
import { getCurrentRoute, subscribe } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getResults, setRefs, setRenderHook, type DomRefs } from './context.js';
import { renderBrowse } from './render-browse.js';
import { renderSearch } from './render-search.js';

/* -------------------------------------------------------------------------
 * Rendering-lifecycle state
 *
 * `unsubscribe` holds the teardown for the CURRENT mount's hashchange listener.
 * `init` clears any previous listener before subscribing a new one, so a
 * re-mount never leaves the old listener on `window` (memory leak fix).
 *
 * `renderToken` is a monotonic counter incremented at the start of every
 * `render()`. Each in-flight render captures its token and, after each `await`,
 * bails out if a newer render has started — preventing a slower, superseded
 * fetch from clobbering the freshest results (render-race fix).
 * ---------------------------------------------------------------------- */
let unsubscribe: (() => void) | null = null;
let renderToken = 0;

/**
 * Bind the freshly-built DOM refs into the shared context, register `render`
 * as the re-render hook, tear down any previous mount's hashchange listener,
 * subscribe a new one, and kick off the initial render.
 */
export function init(refs: DomRefs): void {
  setRefs(refs);
  setRenderHook(render);
  // Tear down the previous mount's listener first (if any) so re-mounts never
  // accumulate hashchange listeners on `window`.
  if (unsubscribe !== null) {
    unsubscribe();
    unsubscribe = null;
  }
  unsubscribe = subscribe(render);
  render();
}

/**
 * Route dispatcher.
 *
 * Clears the results container synchronously (so a pending/failed fetch never
 * leaves a stale table behind) but does NOT clear the breadcrumb or status
 * here. Clearing those synchronously would remove in-page navigation targets
 * in the middle of a click handler: `navigate()` dispatches `hashchange`
 * synchronously in happy-dom, which would re-enter `render` and wipe the
 * breadcrumb before the click's caller can read the next segment. The
 * breadcrumb/status are instead refreshed by `renderBrowse`/`renderSearch`
 * once data arrives.
 */
export async function render(): Promise<void> {
  // Claim this render slot. A newer render increments `renderToken` past
  // `myToken`; after each `await` we bail out if superseded so a slower fetch
  // can never overwrite the freshest results, breadcrumb, or status.
  const myToken = ++renderToken;
  const route = getCurrentRoute();
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  // Debounced spinner: a search fetch only shows a spinner if it is still in
  // flight after 500ms, so fast searches never flash a loading indicator. The
  // timer is cleared on every exit path (success, error, superseded), and its
  // callback also bails if a newer render has claimed the slot — so a slower,
  // superseded fetch can never re-add a stale spinner. For browse routes, no
  // spinner is ever shown. When results do render, the spinner (if shown) is
  // removed naturally: `renderSearch(result)` clears the container before
  // building the table, and the error handler's `textContent` replaces all.
  let spinnerTimer: ReturnType<typeof setTimeout> | null = null;
  const clearSpinnerTimer = (): void => {
    if (spinnerTimer !== null) {
      clearTimeout(spinnerTimer);
      spinnerTimer = null;
    }
  };
  if (route.view === 'search') {
    spinnerTimer = setTimeout(() => {
      spinnerTimer = null;
      // A newer render owns the slot — don't re-add a stale spinner.
      if (myToken !== renderToken) return;
      const spinnerWrap = document.createElement('div');
      spinnerWrap.className = 'search-spinner';
      const spinnerIcon = document.createElement('i');
      spinnerIcon.className = 'bi bi-arrow-repeat spinning';
      spinnerWrap.appendChild(spinnerIcon);
      resultsEl.appendChild(spinnerWrap);
    }, 500);
  }
  try {
    if (route.view === 'browse') {
      const result = await getApi().browse(normalizeRelativePath(route.path));
      clearSpinnerTimer();
      if (myToken !== renderToken) return;
      renderBrowse(result);
    } else {
      const result = await getApi().search(route.query, normalizeRelativePath(route.path));
      clearSpinnerTimer();
      if (myToken !== renderToken) return;
      renderSearch(result);
    }
  } catch (err) {
    clearSpinnerTimer();
    // A superseded render must not even commit its error.
    if (myToken !== renderToken) return;
    // textContent replaces all children, so any stale table is removed too.
    resultsEl.textContent =
      err instanceof Error ? 'Error: ' + err.message : 'Error: ' + String(err);
  }
}

/**
 * Render a {@link BrowseResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Size | Modified | —) with an empty
 * Actions header cell and the browse-table CSS class, plus an optional
 * leading ".." parent row.
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { BrowseResult } from '../api.js';
import { formatBytes } from '../format.js';
import {
  buildTable,
  makeBrowseRow,
  makeParentRow,
  renderBreadcrumb,
  setupDirContextMenu,
} from './dom-builders.js';
import { getResults, getStatus } from './context.js';

export function renderBrowse(result: BrowseResult): void {
  // Breadcrumb (clickable cumulative-path segments)
  renderBreadcrumb(result.path);

  // Status footer: "N folders, M files, total S"
  getStatus().textContent =
    result.folderCount +
    ' folders, ' +
    result.fileCount +
    ' files, total ' +
    formatBytes(result.totalSize);

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Size', 'Modified', '']);
  table.classList.add('browse-table');
  const tbody = table.querySelector('tbody')!;

  if (result.parent !== null) {
    tbody.append(makeParentRow(result.parent));
  }
  for (const entry of result.entries) {
    tbody.append(makeBrowseRow(entry));
  }

  resultsEl.append(table);

  // Mount the current-directory context menu (right-click on blank space) and
  // wire its listener. Rebuilds the menu each render for the current path; the
  // listener attaches once. Must run AFTER the table is appended so the menu
  // is a later sibling (document order) than the row menus inside the table.
  setupDirContextMenu(resultsEl, result.path);
}

/**
 * SPA entry — wires `api`, `router`, and the DOM into a file-browser UI
 * rendered inside a native `<dialog>` widget.
 *
 * This module is the thin entry point: it builds the DOM imperatively, wires
 * toolbar/dialog events, binds the resulting element refs into the render
 * orchestrator (which owns the route dispatch and render lifecycle), and kicks
 * off the initial render. The rendering logic itself lives in the focused
 * modules under `./app/`:
 *
 *   - `./app/context.js`             — shared API client, DOM refs, render hook
 *   - `./app/dom-builders.js`        — table/breadcrumb/row/action-button builders
 *   - `./app/render-browse.js`       — browse-result rendering
 *   - `./app/render-search.js`       — search-result rendering
 *   - `./app/toolbar-handlers.js`    — search + upload-into-folder handlers
 *   - `./app/render-orchestrator.js` — route dispatch + render lifecycle
 *
 * Structure (built imperatively via `document.createElement`):
 *
 *   .file-browser-host   — primary chromeless surface; hosts the widget while
 *                          the dialog is closed (embedded view)
 *   <button class="trigger">Browse Files</button>
 *   <dialog class="browser-dialog">  — frame + titlebar (dialog-only chrome)
 *     .dialog-header     — title <span> + Close icon <button>
 *     .dialog-body        — empty slot; the shared widget moves here on open
 *
 *   The shared .file-browser widget (toolbar + .results + .status) is MOVED
 *   between the embedded host and the dialog body as the dialog opens/closes.
 *   It carries no border/background/title of its own — only the dialog adds
 *   the frame + titlebar, so the embedded view is chromeless.
 *
 *   .file-browser:
 *     toolbar   — .breadcrumb + .search-wrapper (search <input> +
 *                search-icon + clear-btn)
 *     .results  — file/folder <table>
 *     <footer class="status"> — summary line
 *
 * All user-controlled strings (file/folder names, paths) are inserted via
 * `textContent` / element creation — never via `innerHTML` — to prevent HTML
 * injection.
 *
 * `renderBrowse` and `renderSearch` are re-exported so `src/app.test.ts`'s
 * existing `import { startApp, renderBrowse, renderSearch } from './app'`
 * continues to resolve without modification.
 */
import { doSearch, clearSearch } from './app/toolbar-handlers.js';
import { init } from './app/render-orchestrator.js';
import type { DomRefs } from './app/context.js';

export { renderBrowse } from './app/render-browse.js';
export { renderSearch } from './app/render-search.js';

/* =========================================================================
 * startApp — build the DOM, wire events, bind refs, kick off rendering
 * ========================================================================= */

export function startApp(root: HTMLElement): void {
  root.innerHTML = '';

  /* --- File-browser widget (chromeless; shared by the embedded view and the
     dialog). It owns the toolbar, results, and status. The frame and titlebar
     belong to whichever host renders it — never to the widget itself — so when
     it is embedded directly in the page it carries no border/background/title. --- */
  const widget = document.createElement('div');
  widget.className = 'file-browser';

  // Toolbar: breadcrumb, search
  const toolbar = document.createElement('div');
  toolbar.className = 'toolbar';
  const breadcrumbEl = document.createElement('div');
  breadcrumbEl.className = 'breadcrumb';
  const searchInput = document.createElement('input');
  searchInput.type = 'text';
  searchInput.placeholder = 'Search...';
  // Search affordance: a wrapper holding the input, a leading search icon,
  // and a trailing clear button (the latter toggled purely by CSS via
  // `:placeholder-shown`, so it needs no ref in DomRefs).
  const searchWrapper = document.createElement('div');
  searchWrapper.className = 'search-wrapper';
  const searchIcon = document.createElement('i');
  searchIcon.className = 'bi bi-search search-icon';
  const searchClearBtn = document.createElement('button');
  searchClearBtn.className = 'clear-btn';
  searchClearBtn.type = 'button';
  searchClearBtn.setAttribute('aria-label', 'Clear search');
  const clearIcon = document.createElement('i');
  clearIcon.className = 'bi bi-x-lg';
  searchClearBtn.append(clearIcon);
  // ORDER MATTERS: input first, then icon, then clear-btn (CSS uses ~ sibling combinator)
  searchWrapper.append(searchInput, searchIcon, searchClearBtn);
  toolbar.append(breadcrumbEl, searchWrapper);

  // Results container + status footer
  const resultsEl = document.createElement('div');
  resultsEl.className = 'results';
  const statusEl = document.createElement('footer');
  statusEl.className = 'status';

  widget.append(toolbar, resultsEl, statusEl);

  /* --- Embedded host: the primary, chromeless surface. The widget lives here
     while the dialog is closed. --- */
  const embeddedHost = document.createElement('div');
  embeddedHost.className = 'file-browser-host';
  embeddedHost.append(widget);

  /* --- Trigger button --- */
  const trigger = document.createElement('button');
  trigger.className = 'trigger';
  trigger.textContent = 'Browse Files';

  /* --- Native <dialog>: supplies the frame (border/background) and titlebar
     (title + close). Its body is an empty slot the shared widget drops into
     when opened. --- */
  const dialog = document.createElement('dialog');
  dialog.className = 'browser-dialog';

  // Titlebar: centered title + Close (icon) button
  const header = document.createElement('div');
  header.className = 'dialog-header';
  const titleSpan = document.createElement('span');
  titleSpan.className = 'title';
  titleSpan.textContent = 'File Browser';
  const closeBtn = document.createElement('button');
  closeBtn.className = 'close-btn';
  closeBtn.type = 'button';
  // Icon button has no visible text, so expose an accessible name.
  closeBtn.setAttribute('aria-label', 'Close');
  const closeIcon = document.createElement('i');
  closeIcon.className = 'bi bi-x-lg';
  closeBtn.append(closeIcon);
  header.append(titleSpan, closeBtn);

  // Dialog body slot: the widget is moved here on open, back to the host on close.
  const dialogBody = document.createElement('div');
  dialogBody.className = 'dialog-body';

  dialog.append(header, dialogBody);
  root.append(embeddedHost, trigger, dialog);

  /* --- Event wiring --- */
  // Opening the dialog MOVES the shared widget into the dialog body (reusing
  // the same nodes, so the context refs and any in-flight render stay valid),
  // then shows it. Closing — via the close button, ESC, etc. — fires the
  // dialog's `close` event, which moves the widget back to the embedded host.
  trigger.addEventListener('click', () => {
    dialogBody.append(widget);
    dialog.showModal();
  });
  dialog.addEventListener('close', () => {
    embeddedHost.append(widget);
  });
  closeBtn.addEventListener('click', () => dialog.close());

  // Debounced search: re-fire `doSearch` 200ms after the last keystroke so
  // typing a query doesn't pound the API on every character.
  let searchDebounceTimer: ReturnType<typeof setTimeout> | null = null;
  searchInput.addEventListener('input', () => {
    if (searchDebounceTimer !== null) {
      clearTimeout(searchDebounceTimer);
    }
    searchDebounceTimer = setTimeout(() => {
      searchDebounceTimer = null;
      doSearch();
    }, 200);
  });
  // Clear button: wipe the input and return to the browse view.
  searchClearBtn.addEventListener('click', clearSearch);
  searchInput.addEventListener('keydown', (event: KeyboardEvent) => {
    if (event.key === 'Enter') {
      doSearch();
    } else if (event.key === 'Escape') {
      // stopPropagation is critical: when the widget lives inside the open
      // <dialog>, the native ESC-to-close would otherwise dismiss the dialog.
      event.stopPropagation();
      clearSearch();
    }
  });

  /* --- Bind refs into the orchestrator + context, subscribe, and kick off
     the initial render. --- */
  const refs: DomRefs = {
    results: resultsEl,
    status: statusEl,
    breadcrumb: breadcrumbEl,
    searchInput,
  };
  init(refs);
}

/* =========================================================================
 * Bootstrap
 *
 * Guarded so the module is importable in tests (which have no #app element)
 * without side effects. Only mounts when a real #app container exists.
 * ========================================================================= */

const appRoot = document.getElementById('app');
if (appRoot) {
  startApp(appRoot);
}

/**
 * Toolbar event handlers: search submission, search clearing, and upload into
 * an arbitrary folder (via the context-menu / row "Upload" action).
 *
 * They operate against the shared DOM/API context (search input value, current
 * route) and trigger a re-render via the context's render hook.
 */
import { getCurrentRoute, navigate, toBrowseHash, toSearchHash } from '../router.js';
import { normalizeRelativePath } from '../format.js';
import { getApi, getSearchInput, getStatus, rerender } from './context.js';

/**
 * Navigate to a search hash for the current input value and browse path.
 *
 * A query of fewer than two characters (after trimming) does not search: it
 * navigates to the browse route for the current path instead, so the server
 * never receives a too-short `query`. This mirrors the empty-query fallback
 * and keeps the input's text intact (only the route changes).
 */
export function doSearch(): void {
  const path = normalizeRelativePath(getCurrentRoute().path);
  const query = getSearchInput().value.trim();
  if (query.length < 2) {
    navigate(toBrowseHash(path));
    return;
  }
  navigate(toSearchHash(query, path));
}

/**
 * Clear the search input and return to the browse view for the current path.
 *
 * Resets the search input value to an empty string, reads the current path
 * (normalised), and navigates to the browse hash for that path — the same
 * behaviour as {@link doSearch} when the query is too short, but exposed as an
 * explicit, unconditional entry point that also wipes the input text.
 */
export function clearSearch(): void {
  getSearchInput().value = '';
  const path = normalizeRelativePath(getCurrentRoute().path);
  navigate(toBrowseHash(path));
}

/**
 * Open the native file picker and upload every selected file into `dirPath`
 * (an arbitrary directory, NOT necessarily the current route) — used by the
 * folder-row "Upload" and the current-directory context menus.
 *
 * Uses a self-contained, transient `<input type="file" multiple>` appended
 * hidden to body, clicked (within the menu-item click's user gesture so the
 * picker is allowed to open), awaited until either `change` (files chosen) or
 * `cancel` (dismissed), then removed — so a cancel resolves cleanly with no
 * upload and no leak. Each file is uploaded in order; per-file failures are
 * collected and surfaced in the status footer without aborting the rest.
 */
export async function pickAndUploadInto(dirPath: string): Promise<void> {
  const input = document.createElement('input');
  input.type = 'file';
  input.multiple = true;
  input.style.display = 'none';
  document.body.append(input);

  const files = await new Promise<File[]>((resolve) => {
    let settled = false;
    const finish = (list: File[]): void => {
      if (settled) {
        return;
      }
      settled = true;
      resolve(list);
    };
    input.addEventListener('change', () => {
      finish(input.files ? Array.from(input.files) : []);
    });
    // `cancel` fires when the user dismisses the picker without choosing —
    // resolve with an empty list so the input is removed and no upload runs.
    input.addEventListener('cancel', () => finish([]));
    input.click();
  });
  input.remove();

  if (files.length === 0) {
    return;
  }
  const path = normalizeRelativePath(dirPath);
  const failed: string[] = [];
  for (const file of files) {
    try {
      await getApi().upload(path, file);
    } catch {
      failed.push(file.name);
    }
  }
  await rerender();
  if (failed.length > 0) {
    const succeeded = files.length - failed.length;
    getStatus().textContent = `Uploaded ${succeeded} file(s); failed: ${failed.join(', ')}`;
  }
}

